@startuml

package "com" {
  package "iluwatar" {
    package "prototype" {

      abstract class Beast {
        + Beast()
        + clone() : Beast
      }

      abstract class Warlord {
        + Warlord()
        + clone() : Warlord
      }

      abstract class Mage {
        + Mage()
        + clone() : Mage
      }

      abstract class Prototype {
        + Prototype()
        + clone() : Object
      }

      interface HeroFactory {
        + createBeast() : Beast
        + createMage() : Mage
        + createWarlord() : Warlord
      }

      class HeroFactoryImpl {
        - beast : Beast
        - mage : Mage
        - warlord : Warlord
        + HeroFactoryImpl(mage : Mage, warlord : Warlord, beast : Beast)
        + createBeast() : Beast
        + createMage() : Mage
        + createWarlord() : Warlord
      }

      class ElfBeast {
        + ElfBeast()
        + clone() : Beast
        + toString() : String
      }

      class OrcBeast {
        + OrcBeast()
        + clone() : Beast
        + toString() : String
      }

      class ElfWarlord {
        + ElfWarlord()
        + clone() : Warlord
        + toString() : String
      }

      class OrcWarlord {
        + OrcWarlord()
        + clone() : Warlord
        + toString() : String
      }

      class ElfMage {
        + ElfMage()
        + clone() : Mage
        + toString() : String
      }

      class OrcMage {
        + OrcMage()
        + clone() : Mage
        + toString() : String
      }

      class App {
        + App()
        + main(args : String[]) : void
      }

      Beast --|> Prototype
      Warlord --|> Prototype
      Mage --|> Prototype

      ElfBeast --|> Beast
      OrcBeast --|> Beast

      ElfWarlord --|> Warlord
      OrcWarlord --|> Warlord

      ElfMage --|> Mage
      OrcMage --|> Mage

      HeroFactoryImpl ..|> HeroFactory

      HeroFactoryImpl --> Beast : -beast
      HeroFactoryImpl --> Warlord : -warlord
      HeroFactoryImpl --> Mage : -mage

    }
  }
}

@enduml
